const resp = $.steps.readLeads.response || {};
const values = resp.values || [];
if (values.length < 2) return { leads: [], count: 0 };
const leads = values.slice(1).map((row, i) => ({
  index: i + 1,
  name: row[0] || 'Unknown',
  company: row[1] || '',
  email: row[2] || '',
  website: row[3] || '',
  notes: row[4] || ''
})).filter(l => l.company.length > 0);
return { leads: leads.slice(0, 15), count: leads.length };

const leads = $.steps.parseLeads.output.leads || [];
const companies = leads.map(l => l.company).filter(Boolean).slice(0, 5);
const staticTerms = 'company about team funding';
return { query: companies.join(' OR ') + ' ' + staticTerms };

const leads = $.steps.parseLeads.output.leads || [];
const research = $.steps.researchLeads.response.results || [];
let compiled = '';
leads.forEach(l => {
  compiled += '--- LEAD ' + l.index + ' ---\n';
  compiled += 'Name: ' + l.name + '\n';
  compiled += 'Company: ' + l.company + '\n';
  compiled += 'Email: ' + l.email + '\n';
  compiled += 'Website: ' + l.website + '\n';
  compiled += 'Notes: ' + l.notes + '\n';
  const related = research.filter(r => (r.title || '').toLowerCase().includes(l.company.toLowerCase()) || (r.url || '').toLowerCase().includes(l.company.toLowerCase()));
  if (related.length > 0) {
    compiled += 'Research: ' + related.map(r => r.text || '').join(' ').slice(0, 1500) + '\n';
  }
  compiled += '\n';
});
return { compiled: compiled.slice(0, 25000), count: leads.length };

const d = $.steps.compileData.output;
const criteria = $.input.qualificationCriteria;
let prompt = 'You are a senior sales analyst. Qualify these leads against the given criteria.

';
prompt += 'QUALIFICATION CRITERIA: ' + criteria + '

';
prompt += 'LEADS:
' + d.compiled + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Score each lead 1-100
';
prompt += '- Classify: hot (80+), warm (50-79), cold (below 50)
';
prompt += '- Provide reason and next action for each

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "qualifiedLeads": [{
';
prompt += '    "name": "lead name",
';
prompt += '    "company": "company",
';
prompt += '    "score": 85,
';
prompt += '    "classification": "hot|warm|cold",
';
prompt += '    "reason": "why this score",
';
prompt += '    "nextAction": "suggested next step"
';
prompt += '  }],
';
prompt += '  "summary": "pipeline summary",
';
prompt += '  "hotCount": 0, "warmCount": 0, "coldCount": 0
';
prompt += '}';
return { prompt };

let raw = $.steps.aiQualify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { qualifiedLeads: [], summary: raw, hotCount: 0, warmCount: 0, coldCount: 0 }; }

const ai = $.steps.parseAI.output;
const leads = ai.qualifiedLeads || [];
const header = ['Name', 'Company', 'Score', 'Classification', 'Reason', 'Next Action'];
const rows = leads.map(l => [
  l.name || 'Unknown',
  l.company || '',
  String(l.score || 0),
  l.classification || 'cold',
  l.reason || '',
  l.nextAction || ''
]);
return { values: [header].concat(rows), leadCount: leads.length };

const ai = $.steps.parseAI.output;
const leads = ai.qualifiedLeads || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Lead Qualification Complete', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + leads.length + ' leads* qualified' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Hot:* ' + (ai.hotCount || 0) },
  { type: 'mrkdwn', text: '*Warm:* ' + (ai.warmCount || 0) },
  { type: 'mrkdwn', text: '*Cold:* ' + (ai.coldCount || 0) }
] });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary.slice(0, 500) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Exa + Claude AI' }] });

const fallback = 'Lead Qualification: ' + leads.length + ' leads scored, ' + (ai.hotCount || 0) + ' hot';
return { blocks, fallback };
